// Generated by UntilizeCodegen — BRISC writer for untilize + optional unpadding.
// Writes RM sticks from compute to DRAM. Supports both full untilize and
// untilize_with_unpadding by checking stick position against per-batch height.
// Width unpadding: writes unpadded_row_size_bytes per stick (< padded row).
// Height unpadding: skips sticks beyond H_unpadded_per_batch within each batch.
//
// Pipelining (matches ttnn writer_unary_stick_layout_split_rows_multi_core):
// issue ALL sticks of the held tile-row back-to-back, then a SINGLE barrier per
// tile-row. The prior version flushed every 8 sticks (noc_async_writes_flushed),
// capping outstanding DRAM writes to ~8*stick_bytes (64 KiB at 8192 B/stick) —
// well below the bandwidth*latency the DRAM-write pipeline needs to stay busy.
// Issuing all tile_height sticks (up to 256 KiB in flight) before one barrier
// hides write latency and lifts the DRAM-write duty cycle toward ttnn's ceiling.
// Each cb_wait_front holds exactly ONE tile-row and every stick reads a disjoint
// slice of it, so one per-tile-row barrier is sufficient for correct CB reuse —
// identical cadence to ttnn's per-block noc_async_write_barrier.
#include "api/dataflow/dataflow_api.h"

void kernel_main() {
    const uint32_t dst_addr = get_arg_val<uint32_t>(0);
    const uint32_t num_tile_rows = get_arg_val<uint32_t>(1);
    const uint32_t start_stick_id = get_arg_val<uint32_t>(2);
    const uint32_t padded_row_size_bytes = get_arg_val<uint32_t>(3);
    // For unpadding: per-batch unpadded height. If 0, no unpadding.
    // padded_batch_h = physical sticks per batch (Ht * 32).
    // out_page_start = output page ID (excludes padding sticks from prior cores).
    const uint32_t H_unpadded = get_arg_val<uint32_t>(4);
    const uint32_t padded_batch_h = get_arg_val<uint32_t>(5);
    const uint32_t out_page_start = get_arg_val<uint32_t>(6);

    constexpr uint32_t cb_out = get_compile_time_arg_val(0);
    constexpr uint32_t unpadded_row_size_bytes = get_compile_time_arg_val(1);
    constexpr auto dst_args = TensorAccessorArgs<2>();
    constexpr uint32_t num_tiles_per_row = get_compile_time_arg_val(dst_args.next_compile_time_args_offset());

    constexpr uint32_t tile_height = 32;

    // The logical row payload can be narrower than the destination buffer's
    // aligned physical page. Use the accessor pitch for page addressing and
    // retain ``unpadded_row_size_bytes`` only as the write length.
    const uint32_t destination_page_size = dst_args.get_aligned_page_size();
    const auto d = TensorAccessor(dst_args, dst_addr, destination_page_size);

    uint32_t stick_id = start_stick_id;
    uint32_t out_stick_id = (H_unpadded > 0) ? out_page_start : start_stick_id;
    bool do_unpad = (H_unpadded > 0);

    for (uint32_t tr = 0; tr < num_tile_rows; ++tr) {
        cb_wait_front(cb_out, num_tiles_per_row);
        uint32_t l1_read_addr = get_read_ptr(cb_out);

        // Issue every valid stick of this tile-row before syncing (no
        // intermediate flush) so up to tile_height writes are in flight.
        for (uint32_t row = 0; row < tile_height; ++row) {
            // Per-batch check: stick position within the current batch
            // must be < H_unpadded (the per-batch valid height).
            bool valid = !do_unpad || ((stick_id % padded_batch_h) < H_unpadded);
            if (valid) {
                uint64_t dst_noc_addr = get_noc_addr(out_stick_id, d);
                noc_async_write(l1_read_addr, dst_noc_addr, unpadded_row_size_bytes);
                out_stick_id++;
            }
            l1_read_addr += padded_row_size_bytes;
            stick_id++;
        }

        // Single barrier per tile-row (ttnn per-block cadence): drains all
        // writes so the CB slot is safe to reuse. A no-op if 0 sticks issued.
        noc_async_write_barrier();

        cb_pop_front(cb_out, num_tiles_per_row);
    }
}
